const raw = $input.first().json.body || $input.first().json;
const action = String(raw.action || '').toLowerCase();
const validActions = ['complete_draft','cancel_draft','cancel_order'];
if (!validActions.includes(action)) {
  throw new Error('invalid_action â€” must be one of: ' + validActions.join(','));
}

const draft_id = String(raw.draft_order_id || '').replace(/\D/g, '');
const order_id = String(raw.order_id || '').replace(/\D/g, '');
const application_code = String(raw.application_code || '');
const wp_post_id = Number(raw.wp_post_id) || null;

if (action === 'cancel_order' && !order_id) {
  throw new Error('missing_order_id â€” cancel_order requires order_id');
}
if ((action === 'complete_draft' || action === 'cancel_draft') && !draft_id) {
  throw new Error('missing_draft_order_id â€” ' + action + ' requires draft_order_id');
}

const draft_gid = draft_id ? `gid://shopify/DraftOrder/${draft_id}` : null;
const order_gid = order_id ? `gid://shopify/Order/${order_id}` : null;
const reason = raw.reason || 'DECLINED';
const propagate_to = Array.isArray(raw.propagate_to_post_ids) ? raw.propagate_to_post_ids.map(Number).filter(Boolean) : [];

return [{ json: {
  action,
  wp_post_id,
  application_code,
  draft_id,
  draft_gid,
  order_id,
  order_gid,
  reason,
  propagate_to,
} }];

const ctx = $('Validate + Lookup WP').first().json;
const resp = $input.first().json || {};
const data = resp?.data?.draftOrderComplete || {};
const errs = data.userErrors || [];
const order = data.draftOrder?.order;
let result;
if (!order || errs.length) {
  result = {
    ...ctx,
    ok: false,
    error: errs.length ? JSON.stringify(errs).slice(0, 300) : 'no_order_in_response',
    raw: JSON.stringify(resp).slice(0, 500),
  };
} else {
  const m = order.id.match(/(\d+)$/);
  result = {
    ...ctx,
    ok: true,
    new_meta: {
      shopify_order_id: m ? m[1] : '',
      shopify_order_gid: order.id,
      shopify_order_name: order.name || '',
      shopify_order_fulfillment_status: String(order.displayFulfillmentStatus || '').toLowerCase(),
      shopify_order_financial_status: String(order.displayFinancialStatus || '').toLowerCase(),
      shopify_status: 'order_unfulfilled',
      shopify_last_sync_at: new Date().toISOString().replace('T',' ').slice(0,19),
      shopify_last_error: '',
    },
  };
}
return [{ json: result }];

const ctx = $('Validate + Lookup WP').first().json;
const resp = $input.first().json || {};
const data = resp?.data?.draftOrderDelete || {};
const errs = data.userErrors || [];
let result;
if (errs.length) {
  result = { ...ctx, ok: false, error: JSON.stringify(errs).slice(0, 300) };
} else {
  result = {
    ...ctx,
    ok: true,
    new_meta: {
      shopify_status: 'draft_deleted',
      shopify_last_sync_at: new Date().toISOString().replace('T',' ').slice(0,19),
      shopify_last_error: '',
    },
  };
}
return [{ json: result }];

const ctx = $('Validate + Lookup WP').first().json;
const resp = $input.first().json || {};
const data = resp?.data?.orderCancel || {};
const errs = data.orderCancelUserErrors || [];
let result;
if (errs.length) {
  result = { ...ctx, ok: false, error: JSON.stringify(errs).slice(0, 300) };
} else {
  result = {
    ...ctx,
    ok: true,
    new_meta: {
      shopify_status: 'order_cancelled',
      shopify_order_fulfillment_status: 'cancelled',
      shopify_last_sync_at: new Date().toISOString().replace('T',' ').slice(0,19),
      shopify_last_error: '',
    },
  };
}
return [{ json: result }];
